{%- set data = engine.query_stream_data(stream="ai_mcp_prompt_templates") -%}
{%- set prompt_template_name = prompt_template_name -%}
{%- set version = version | default(current_version) -%}
{%- set config_data_for_template = (data | selectattr("prompt_template_name", "equalto", prompt_template_name) | list) -%}
{%- if ai_project_name -%}
  {%- set config_data_for_template = (config_data_for_template | selectattr("ai_project_name", "equalto", ai_project_name) | list) -%}
{%- endif -%}
{%- set lhs_output = (config_data_for_template | selectattr("version", "equalto", version) | map(attribute="prompt_template") | list | first) -%}
{%- set rhs_output = (config_data_for_template | selectattr("version", "equalto", compare_version) | map(attribute="prompt_template") | list | first) -%}

<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0"/>
  <title>Prompt Template Diff Viewer</title>
  <style>
    html, body {
      margin: 0;
      padding: 0;
      height: 100%;
      width: 100%;
      background: #1e1e2f;
      color: #ffffff;
      font-family: "Segoe UI", Roboto, sans-serif;
    }

    #version-heading {
      text-align: center;
      padding: 12px 0;
      background: #2b2b3d;
      font-size: 17px;
      font-weight: 600;
      border-bottom: 1px solid #3a3a4d;
      letter-spacing: 0.3px;
    }

    #version-heading span {
      color: #7dcfff;
    }

    #diff-container {
      height: calc(100% - 50px);
      width: 100%;
    }
  </style>
  <script src="https://cdnjs.cloudflare.com/ajax/libs/require.js/2.3.6/require.min.js"></script>
</head>
<body>
  <div id="version-heading">
    Prompt Template Difference for: <span>{{ prompt_template_name }}</span><br/>
    {% if ai_project_name %}<span>Project: {{ ai_project_name }}</span><br/>{% endif %}
    Comparing <span>Version {{ version }}</span> → <span>Version {{ compare_version }}</span>
  </div>

  <div id="diff-container"></div>

  <script>
    const lhs = {{ lhs_output | default("") | tojson }};
    const rhs = {{ rhs_output | default("") | tojson }};

    window.require.config({
      paths: {
        vs: "https://cdn.jsdelivr.net/npm/monaco-editor@0.45.0/min/vs"
      }
    });

    window.require(["vs/editor/editor.main"], function () {
      const container = document.getElementById("diff-container");

      if (!lhs || !rhs) {
        container.innerText = "Something went wrong: missing config data. Please ensure both versions exist and contain data.";
        return;
      }

      const originalModel = monaco.editor.createModel(lhs, "text/plain");
      const modifiedModel = monaco.editor.createModel(rhs, "text/plain");

      monaco.editor.createDiffEditor(container, {
        theme: "vs-dark",
        readOnly: true,
        enableSplitViewResizing: true,
        automaticLayout: true
      }).setModel({
        original: originalModel,
        modified: modifiedModel
      });
    });
  </script>
</body>
</html>

