<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0"/>
  <title>Prompt Template Diff Viewer</title>
  <style>
    html, body {
      margin: 0;
      padding: 0;
      height: 100%;
      width: 100%;
      background: #1e1e2f;
      color: #ffffff;
      font-family: "Segoe UI", Roboto, sans-serif;
    }

    /* Centered top header for name + project */
    #header {
      background: #2b2b3d;
      border-bottom: 1px solid #3a3a4d;
      padding: 10px 0;
      text-align: center;
    }

    #header .title {
      font-size: 18px;
      font-weight: 600;
    }

    #header .project {
      color: #7dcfff;
      font-size: 15px;
      margin-top: 3px;
    }

    /* Version bar with proper left alignment */
    #version-row {
      display: grid;
      grid-template-columns: 1fr 1fr;
      background: #24243a;
      border-bottom: 1px solid #3a3a4d;
      padding: 6px 20px;
      font-size: 14px;
      color: #c8c8dc;
      font-weight: 500;
    }

    .version-label {
      display: flex;
      align-items: center;
    }

    .version-label span {
      color: #7dcfff;
      font-weight: 600;
    }

    /* Make right label start at left of right editor */
    .version-label.right {
      justify-content: flex-start;
      padding-left: 10px;
    }

    #diff-container {
      height: calc(100% - 110px);
      width: 100%;
    }
  </style>

  <script src="https://cdnjs.cloudflare.com/ajax/libs/require.js/2.3.6/require.min.js"></script>
</head>
<body>
  <div id="header">
    <div class="title">Prompt Template Difference for: <span>{{ prompt_template_name }}</span></div>
    {% if ai_project_name %}
      <div class="project">Project: {{ ai_project_name }}</div>
    {% endif %}
  </div>

  <div id="version-row">
    <div class="version-label left">Current Version: <span>{{ version }}</span></div>
    <div class="version-label right">Comparison Version: <span>{{ compare_version }}</span></div>
  </div>

  <div id="diff-container"></div>

  <script>
    const lhs = {{ lhs_output | default("") | tojson }};
    const rhs = {{ rhs_output | default("") | tojson }};

    window.require.config({
      paths: {
        vs: "https://cdn.jsdelivr.net/npm/monaco-editor@0.45.0/min/vs"
      }
    });

    window.require(["vs/editor/editor.main"], function () {
      const container = document.getElementById("diff-container");

      if (!lhs || !rhs) {
        container.innerText = "Something went wrong: missing config data. Please ensure both versions exist and contain data.";
        return;
      }

      const originalModel = monaco.editor.createModel(lhs, "text/plain");
      const modifiedModel = monaco.editor.createModel(rhs, "text/plain");

      monaco.editor.createDiffEditor(container, {
        theme: "vs-dark",
        readOnly: true,
        enableSplitViewResizing: true,
        automaticLayout: true
      }).setModel({
        original: originalModel,
        modified: modifiedModel
      });
    });
  </script>
</body>
</html>
